#!/usr/bin/perl
use strict;
use warnings;
use Device::USB;
use Device::USB::Device;

# Configuración del dispositivo USB
my $vendor_id = 0x1234;  # Reemplazar con el ID real del fabricante
my $product_id = 0x5678; # Reemplazar con el ID real del producto

# Buscar el dispositivo USB
my $usb = Device::USB->new();
my $device = $usb->find_device($vendor_id, $product_id);

if (!$device) {
    die "Dispositivo no encontrado.\n";
}

# Abrir el dispositivo
$device->open();

# Configurar el endpoint para lectura
my $endpoint = 0x81; # Endpoint de entrada (ejemplo)
my $buffer_size = 64;

# Leer pulsaciones del teclado
while (1) {
    my $buffer = '';
    my $result = $device->bulk_transfer($endpoint, $buffer, $buffer_size, 1000);

    if ($result > 0) {
        # Procesar los datos recibidos
        print "Gargun pulsaciones: " . unpack("H*", $buffer) . "\n";
    }
}

# Cerrar el dispositivo
$device->close();
